+// Returns nil if content is empty.
+func splitPromptContent(content string) []string {
+	if content == "" {
+		return nil
+	}
+	parts := strings.Split(content, "\n\n---\n\n")
+	var result []string
+	for _, p := range parts {
+		trimmed := strings.TrimSpace(p)
+		if trimmed != "" {
+			result = append(result, trimmed)
+		}
+	}
+	return result
